css:
.loader {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
  width: 70px;
  height: 50px;
  box-sizing: border-box;
  background:conic-gradient(from 135deg at top,#0000, var(--loader-bg, #ffffff) 1deg 90deg,#0000 91deg) right -20px bottom 8px/18px 9px,linear-gradient(var(--loader-bg, #ffffff) 0 0) bottom/100% 8px,currentColor;
  background-repeat: no-repeat;
  border-bottom: 8px solid currentColor;
  position: relative;
  animation: l7-0 2s infinite linear;
}.loader::before {content: "";
  position: absolute;
  width: 10px;
  height: 14px;
  background: var(--loader-secondary-color, #c084fc);
  left: 10px;
  animation: l7-1 2s infinite cubic-bezier(0,200,1,200);
}@keyframes l7-0{100%  {
  background-position: left -20px bottom 8px,bottom}}@keyframes l7-1{0%,50% {bottom: 8px}90%,100% {bottom: 8.1px}}
